async () => {
  const [rfpsRes, readRes] = await Promise.all([
    scout.getRfps({ limit: 100 }),
    codemode.skill.read('skills.lumenloop.scf-submission-radar', { sections: ['when-to-use-this-skill', 'pointers'] })
  ]);

  const rfps = rfpsRes.ok ? (rfpsRes.data.rfps || []) : [];
  const terms = ['passkey', 'passkeys', 'smart account', 'smart accounts', 'webauthn', 'wallet'];
  const matched = rfps.filter(r => {
    const text = [r.title, r.description, r.category, r.tags, r.status].flat().filter(Boolean).join(' ').toLowerCase();
    return terms.some(t => text.includes(t));
  }).map(r => ({
    id: r.id || r.slug || null,
    title: r.title,
    category: r.category,
    status: r.status,
    open: r.status ? String(r.status).toLowerCase().includes('open') : null,
    deadline: r.deadline || r.due_date || r.closing_date || null,
    url: r.url || r.link || null,
    snippet: r.description ? r.description.slice(0, 180) : null
  }));

  const openMatched = matched.filter(r => r.open !== false);
  return {
    asOf: new Date().toISOString(),
    rfpsCall: rfpsRes.ok ? { count: rfps.length } : { error: rfpsRes.error },
    skillNote: readRes.ok ? readRes.content.slice(0, 500) : readRes.error,
    matchedCount: matched.length,
    openMatchedCount: openMatched.length,
    openMatched: openMatched.slice(0, 8)
  };
}

