async () => {
  const [projectsRes, skillRes] = await Promise.all([
    scout.searchProjects({ category: 'Infrastructure', limit: 20 }),
    codemode.skill.read('skills.lumenloop.stellar-ecosystem-scout', { sections: ['output-the-landscape', 'the-scouting-recipe', 'gotchas'] })
  ]);

  const projects = projectsRes.ok ? (projectsRes.data.projects || []) : [];
  const scored = projects
    .map(p => ({
      name: p.name,
      slug: p.slug,
      category: p.category,
      status: p.status,
      basis: [
        p.githubStars != null ? `${p.githubStars} GitHub stars` : null,
        p.githubCommits30d != null ? `${p.githubCommits30d} commits/30d` : null,
        p.githubOpenIssues != null ? `${p.githubOpenIssues} open issues` : null,
        p.recentActivity != null ? `recent activity: ${p.recentActivity}` : null,
        p.lastUpdated != null ? `updated ${p.lastUpdated}` : null
      ].filter(Boolean)
    }))
    .filter(p => p.basis.length > 0)
    .sort((a, b) => (b.basis.length - a.basis.length) || a.name.localeCompare(b.name))
    .slice(0, 5);

  return {
    projects: scored,
    projectCountSeen: projects.length,
    searchOk: projectsRes.ok,
    searchError: projectsRes.ok ? null : projectsRes.error,
    skill: skillRes.ok ? { sections: skillRes.sections || skillRes.content?.sections ? undefined : undefined } : { error: skillRes.error }
  };
}

